void
InstructionDecoderTestGenerator::startup()
{
    DPRINTF(InstructionDecoderTestGenerator, "Starting instruction decoder tests, total %zu vectors\n", testVectors.size());
    
    for (size_t i = 0; i < testVectors.size(); i++) {
        TestVector& vec = testVectors[i];
        
        dut.setInstruction(vec.instruction);
        dut.process();
        
        bool pass = true;
        if (dut.getOpcode() != vec.opcode) pass = false;
        if (dut.getFunct3() != vec.funct3) pass = false;
        if (dut.getFunct7() != vec.funct7) pass = false;
        if (dut.getRd() != vec.rd) pass = false;
        if (dut.getRs1() != vec.rs1) pass = false;
        if (dut.getRs2() != vec.rs2) pass = false;
        if (dut.getIsRType() != vec.is_r_type) pass = false;
        if (dut.getIsIType() != vec.is_i_type) pass = false;
        if (dut.getIsSType() != vec.is_s_type) pass = false;
        if (dut.getIsBType() != vec.is_b_type) pass = false;
        if (dut.getIsUType() != vec.is_u_type) pass = false;
        if (dut.getIsJType() != vec.is_j_type) pass = false;
        if (dut.getIsJalr() != vec.is_jalr) pass = false;
        if (dut.getIsLui() != vec.is_lui) pass = false;
        if (dut.getIsAuipc() != vec.is_auipc) pass = false;
        if (dut.getIsLoad() != vec.is_load) pass = false;
        if (dut.getIsStore() != vec.is_store) pass = false;
        if (dut.getIsAluReg() != vec.is_alu_reg) pass = false;
        if (dut.getIsAluImm() != vec.is_alu_imm) pass = false;
        if (dut.getAluOp() != vec.alu_op) pass = false;
        if (dut.getMemOp() != vec.mem_op) pass = false;
        if (dut.getRegWrite() != vec.reg_write) pass = false;
        if (dut.getMemRead() != vec.mem_read) pass = false;
        if (dut.getMemWrite() != vec.mem_write) pass = false;
        if (dut.getIsBranch() != vec.is_branch) pass = false;
        if (dut.getBranchOp() != vec.branch_op) pass = false;
        if (dut.getIsCsr() != vec.is_csr) pass = false;
        if (dut.getCsrOp() != vec.csr_op) pass = false;
        if (dut.getCsrUseImm() != vec.csr_use_imm) pass = false;
        if (dut.getIsMul() != vec.is_mul) pass = false;
        if (dut.getIsDiv() != vec.is_div) pass = false;
        if (dut.getIsMret() != vec.is_mret) pass = false;
        if (dut.getIsEcall() != vec.is_ecall) pass = false;
        if (dut.getIsEbreak() != vec.is_ebreak) pass = false;
        if (dut.getIsNop() != vec.is_nop) pass = false;
        if (dut.getIsFence() != vec.is_fence) pass = false;
        
        if (pass) {
            passed++;
            DPRINTF(InstructionDecoderTestGenerator, "Test TP%03d PASSED\n", (int)(i + 1));
        } else {
            failed++;
            DPRINTF(InstructionDecoderTestGenerator, "Test TP%03d FAILED\n", (int)(i + 1));
        }
    }
    
    DPRINTF(InstructionDecoderTestGenerator, "Tests complete: %d passed, %d failed, %d total\n",
            (int)passed, (int)failed, (int)testVectors.size());
    
    if (failed > 0) {
        panic("InstructionDecoderTestGenerator: %d tests failed!", (int)failed);
    }
    
    exitSimLoop("InstructionDecoderTestGenerator complete");
}

